"""
Mẫu Test Webhook G-Labs Automation (Phiên bản ĐẦY ĐỦ - Demo chia sẻ)
Tệp này bao gồm tất cả các tính năng: Image Ref, Whisk, Upscale, Video Modes (Start, Start-End, Components), Resolution.
Dữ liệu API Key và Ảnh đã được nhúng sẵn.
"""
import requests
import time
import json
import os

# 1. Cấu hình cơ bản
BASE_URL = "http://127.0.0.1:8765"
API_KEY = "2HEtWYzGRMYyr6aIwG8SH8jsWSioH9a_LccNzlC1LwA"

# 2. Dữ liệu ảnh mẫu (Base64) - Để người dùng không cần chuẩn bị file ảnh cục bộ
IMG_BASE64_1 = "data:image/png;base64,"
IMG_BASE64_2 = "data:image/jpeg;base64,"

# --- Các hàm hỗ trợ (Helpers) ---

def post_api(endpoint, payload):
    """Gửi yêu cầu POST tới Webhook API với Header xác thực."""
    print(f"\n[POST] Gửi yêu cầu tới {endpoint}...")
    try:
        resp = requests.post(
            f"{BASE_URL}{endpoint}",
            headers={"X-API-Key": API_KEY, "Content-Type": "application/json"},
            json=payload,
            timeout=20,
        )
        return resp.status_code, resp.json()
    except Exception as e:
        print(f"❌ Lỗi kết nối: {e}")
        return 500, {"error": str(e)}

def poll_task(task_id, label="", timeout=400):
    """Theo dõi trạng thái của Task cho đến khi hoàn thành."""
    print(f"\n⏳ Đang kiểm tra trạng thái [{label}] (ID: {task_id})...")
    start = time.time()
    while time.time() - start < timeout:
        try:
            resp = requests.get(
                f"{BASE_URL}/api/status/{task_id}",
                headers={"X-API-Key": API_KEY},
                timeout=10,
            )
            data = resp.json()
            status = data.get("status", "unknown")
            elapsed = int(time.time() - start)

            if status == "completed":
                results = data.get("results", [])
                print(f"   ✅ [{elapsed}s] HOÀN THÀNH! Đã tạo {len(results)} tệp.")
                for i, url in enumerate(results, 1):
                    print(f"      [{i}] Link tải: {url}")
                return True, data
            elif status == "failed":
                err = data.get("error", "Lỗi không xác định")
                print(f"   ❌ [{elapsed}s] THẤT BẠI: {err}")
                return False, data
            
            print(f"   [{elapsed}s] Trạng thái: {status}...")
            time.sleep(5)
        except Exception as e:
            print(f"   ⚠️ Lỗi khi kiểm tra trạng thái: {e}")
            time.sleep(5)

    print(f"   ⏰ Hết thời gian chờ (Timeout) sau {timeout}s")
    return False, {}


# --- Các kịch bản Test chi tiết ---

